INSERT INTO cm.cm_sectype_params (id, uuid, base_cm_sectype_uuid, security_type, bill_bond_indicator, currency, issuer, sale_method, min_denomination, coupon_payment_freq, source_of_funds, enable_reopen, enable_subtypes, enable_retail, enable_institutional, enable_comp_bids, enable_noncomp_bids, enable_negative_yields, enable_auction_safeguards, enable_underbidding, enable_allotment_limits, retail_allotment_in_omega, bound_offset, underbidding_percentile, overall_issue_limit_pd, overall_issue_limit_nonpd, ind_noncomp_limit_pd, ind_noncomp_limit_nonpd, overall_noncomp_limit, ssb_aggregate_limit, public_offer_issue_limit, min_tender_amount, default_mas_a_amount, mas_max_notional, mas_max_pct, max_allotment_per_issuance, calendar_freq, primary_issue_day, ssb_announcement_day, announcement_day_offset, auction_day_offset, size_announcement_day_offset, announcement_footnotes, footnotes_reopen_addendum, calendar_footnotes, coupon_rate_desc, yield_price_desc, comp_app_desc, noncomp_app_desc, eligible_applicants_desc, created_by, updated_by, created_dt, updated_dt, version, is_deleted, is_migrated) VALUES (150000000000002, '3ad69bf3-5d2a-4e8e-a5e7-ca089038244f', '3ad69bf3-5d2a-4e8e-a5e7-ca089038244f', 'SECTYPE_CMTB', 'BILL', 'SGD', 'Monetary Authority of Singapore', 'MOSALE_UNIFORM_PRICE', 1000, NULL, NULL, 'Y', 'N', 'Y', 'Y', 'Y', 'N', 'N', 'Y', 'Y', 'Y', 'N', 5, 25.00, 15.00, 5.00, 40.00, 50000, 0.00, NULL, NULL, 1000, NULL, 290000000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>For individual investors, the initial amount debited for reopened bonds at application will be 115% of the bid amount. This is to take into account capital gains and accrued interest since the final purchase price of the reopened bond will only be determined after the auction.</p><p>If the investor''s bid is successful, the difference between the final purchase price and the initial amount collected will be credited into or debited from the investor''s bank account after the auction, depending on whether the final purchase price is lower or higher than 115% of the bid amount.</p><p>The auction results, including the final yield and purchase price, will be published after the auction.</p>', '<ul>
INSERT INTO cm.cm_sectype_params (id, uuid, base_cm_sectype_uuid, security_type, bill_bond_indicator, currency, issuer, sale_method, min_denomination, coupon_payment_freq, source_of_funds, enable_reopen, enable_subtypes, enable_retail, enable_institutional, enable_comp_bids, enable_noncomp_bids, enable_negative_yields, enable_auction_safeguards, enable_underbidding, enable_allotment_limits, retail_allotment_in_omega, bound_offset, underbidding_percentile, overall_issue_limit_pd, overall_issue_limit_nonpd, ind_noncomp_limit_pd, ind_noncomp_limit_nonpd, overall_noncomp_limit, ssb_aggregate_limit, public_offer_issue_limit, min_tender_amount, default_mas_a_amount, mas_max_notional, mas_max_pct, max_allotment_per_issuance, calendar_freq, primary_issue_day, ssb_announcement_day, announcement_day_offset, auction_day_offset, size_announcement_day_offset, announcement_footnotes, footnotes_reopen_addendum, calendar_footnotes, coupon_rate_desc, yield_price_desc, comp_app_desc, noncomp_app_desc, eligible_applicants_desc, created_by, updated_by, created_dt, updated_dt, version, is_deleted, is_migrated) VALUES (150000000000003, 'f5e1f54b-e84f-4e91-ad4f-6b0e50782f01', 'f5e1f54b-e84f-4e91-ad4f-6b0e50782f01', 'SECTYPE_MASBILL', 'BILL', 'SGD', 'Monetary Authority of Singapore', 'MOSALE_UNIFORM_PRICE', 1000, NULL, NULL, 'Y', 'N', 'Y', 'Y', 'Y', 'N', 'N', 'Y', 'Y', 'Y', 'N', 5, 25.00, 15.00, 5.00, 40.00, 50000, 0.00, NULL, NULL, 1000, NULL, 290000000, NULL, NULL, NULL, 'Friday', NULL, 4, 3, NULL, '<p>Applications to subscribe for MAS Bills may be made only by institutional investors as defined in Section 4A of the Securities and Futures Act (Cap.289) ("institutional investor"). Any application submitted by an entity or person other than an institutional investor will be rejected.</p>
INSERT INTO cm.cm_sectype_params (id, uuid, base_cm_sectype_uuid, security_type, bill_bond_indicator, currency, issuer, sale_method, min_denomination, coupon_payment_freq, source_of_funds, enable_reopen, enable_subtypes, enable_retail, enable_institutional, enable_comp_bids, enable_noncomp_bids, enable_negative_yields, enable_auction_safeguards, enable_underbidding, enable_allotment_limits, retail_allotment_in_omega, bound_offset, underbidding_percentile, overall_issue_limit_pd, overall_issue_limit_nonpd, ind_noncomp_limit_pd, ind_noncomp_limit_nonpd, overall_noncomp_limit, ssb_aggregate_limit, public_offer_issue_limit, min_tender_amount, default_mas_a_amount, mas_max_notional, mas_max_pct, max_allotment_per_issuance, calendar_freq, primary_issue_day, ssb_announcement_day, announcement_day_offset, auction_day_offset, size_announcement_day_offset, announcement_footnotes, footnotes_reopen_addendum, calendar_footnotes, coupon_rate_desc, yield_price_desc, comp_app_desc, noncomp_app_desc, eligible_applicants_desc, created_by, updated_by, created_dt, updated_dt, version, is_deleted, is_migrated) VALUES (150000000000004, '1792cbdd-9265-41f2-828b-377cb54ab691', '1792cbdd-9265-41f2-828b-377cb54ab691', 'SECTYPE_SGS', 'BOND', 'SGD', 'Monetary Authority of Singapore', 'MOSALE_UNIFORM_PRICE', 1000, 'SEMI_ANNUALLY', NULL, 'Y', 'Y', 'Y', 'Y', 'Y', 'Y', 'N', 'Y', 'Y', 'Y', 'N', 5, 25.00, 15.00, 5.00, 40.00, 50000, 40.00, NULL, NULL, 1000, NULL, 290000000, NULL, NULL, NULL, '1', NULL, 7, 3, 7, NULL, '<p>For individual investors, the initial amount debited for reopened bonds at application will be 115% of the bid amount. This is to take into account capital gains and accrued interest since the final purchase price of the reopened bond will only be determined after the auction.</p><p>If the investor''s bid is successful, the difference between the final purchase price and the initial amount collected will be credited into or debited from the investor''s bank account after the auction, depending on whether the final purchase price is lower or higher than 115% of the bid amount.</p><p>The auction results, including the final yield and purchase price, will be published after the auction.</p>', '<ul>
INSERT INTO cm.cm_sectype_params (id, uuid, base_cm_sectype_uuid, security_type, bill_bond_indicator, currency, issuer, sale_method, min_denomination, coupon_payment_freq, source_of_funds, enable_reopen, enable_subtypes, enable_retail, enable_institutional, enable_comp_bids, enable_noncomp_bids, enable_negative_yields, enable_auction_safeguards, enable_underbidding, enable_allotment_limits, retail_allotment_in_omega, bound_offset, underbidding_percentile, overall_issue_limit_pd, overall_issue_limit_nonpd, ind_noncomp_limit_pd, ind_noncomp_limit_nonpd, overall_noncomp_limit, ssb_aggregate_limit, public_offer_issue_limit, min_tender_amount, default_mas_a_amount, mas_max_notional, mas_max_pct, max_allotment_per_issuance, calendar_freq, primary_issue_day, ssb_announcement_day, announcement_day_offset, auction_day_offset, size_announcement_day_offset, announcement_footnotes, footnotes_reopen_addendum, calendar_footnotes, coupon_rate_desc, yield_price_desc, comp_app_desc, noncomp_app_desc, eligible_applicants_desc, created_by, updated_by, created_dt, updated_dt, version, is_deleted, is_migrated) VALUES (150000000000008, 'd5d4ee6a-7f47-44d6-acb2-122d3c7756f0', 'd5d4ee6a-7f47-44d6-acb2-122d3c7756f0', 'SECTYPE_SSB', 'BOND', 'SGD', 'Monetary Authority of Singapore', 'MOSALE_QTY_CEILING', 500, 'SEMI_ANNUALLY', NULL, 'Y', 'N', 'Y', 'N', 'N', 'N', 'N', 'Y', 'Y', 'Y', 'N', 5, 25.00, 15.00, 5.00, 40.00, 50000, 0.00, NULL, NULL, 500, NULL, 290000000, NULL, NULL, NULL, NULL, NULL, NULL, 3, NULL, '<p>Individuals with Supplementary Retirement Scheme (SRS) accounts can use their SRS funds to apply for Singapore Savings Bonds via Internet Banking.</p>
INSERT INTO cm.cm_sectype_params (id, uuid, base_cm_sectype_uuid, security_type, bill_bond_indicator, currency, issuer, sale_method, min_denomination, coupon_payment_freq, source_of_funds, enable_reopen, enable_subtypes, enable_retail, enable_institutional, enable_comp_bids, enable_noncomp_bids, enable_negative_yields, enable_auction_safeguards, enable_underbidding, enable_allotment_limits, retail_allotment_in_omega, bound_offset, underbidding_percentile, overall_issue_limit_pd, overall_issue_limit_nonpd, ind_noncomp_limit_pd, ind_noncomp_limit_nonpd, overall_noncomp_limit, ssb_aggregate_limit, public_offer_issue_limit, min_tender_amount, default_mas_a_amount, mas_max_notional, mas_max_pct, max_allotment_per_issuance, calendar_freq, primary_issue_day, ssb_announcement_day, announcement_day_offset, auction_day_offset, size_announcement_day_offset, announcement_footnotes, footnotes_reopen_addendum, calendar_footnotes, coupon_rate_desc, yield_price_desc, comp_app_desc, noncomp_app_desc, eligible_applicants_desc, created_by, updated_by, created_dt, updated_dt, version, is_deleted, is_migrated) VALUES (150000000000009, '336d1b56-97bb-40e0-a851-e711e8365731', '336d1b56-97bb-40e0-a851-e711e8365731', 'SECTYPE_TBILL', 'BILL', 'SGD', 'Monetary Authority of Singapore', 'MOSALE_UNIFORM_PRICE', 1000, NULL, NULL, 'Y', 'N', 'Y', 'Y', 'Y', 'Y', 'N', 'Y', 'Y', 'Y', 'N', 5, 25.00, 15.00, 5.00, 40.00, 50000, 40.00, NULL, NULL, 1000, NULL, 290000000, NULL, NULL, NULL, 'Tuesday', NULL, 8, 3, NULL, '<p>Applications must be submitted through Primary Dealers and be in time for Primary Dealers to submit by the closing date of application.</p>
